sub escape_xml {
  my ($text) = @_;
  $text =~ s/&/&amp;/g;
  $text =~ s/</&lt;/g;
  $text =~ s/>/&gt;/g;
  return $text;
}

sub paragraph {
  my ($id, $lines) = @_;
  print qq{        <p id="$id">\n};
  for my $line (@$lines) {
    print qq{          $line\n};
  }
  print qq{        </p>\n};
}

sub render_block {
  my ($language, $content) = @_;
  $content = escape_xml($content);
  chomp $content;
  print qq{        <div class="wrapper"><pre class="prettyprint"><code class="language-$language">\n};
  print $content . "\n";
  print qq{</code></pre></div>};
}

sub read_config {
  my ($text) = @_;
  $text =~ m{/\*xml\n(.*?)\n\*/}s or die 'No xml config found';
  return $1;
}

sub read_code {
  my ($text) = @_;
  $text =~ m{// xdoc section -- start\n(.*?)\n// xdoc section -- end}s or die 'No xdoc section found';
  return $1;
}

print qq{      <subsection name="Examples" id="Indentation_Examples">\n};
for my $i (0 .. $#examples) {
  my $example = $examples[$i];
  my $n = $example->{n};
  my $text = path($dir, "Example$n.java")->slurp_utf8;

  if ($example->{config}) {
    paragraph("Example$n-config", $example->{config});
    render_block('xml', read_config($text));
    print "\n";
  }

  paragraph("Example$n-code", $example->{code});
  render_block('java', read_code($text));
  if ($i != $#examples) {
    print qq{<hr class="example-separator"/>};
  }
  print "\n";
}
print qq{      </subsection>\n};
