use strict;
use warnings;

my $dir = 'src/xdocs-examples/resources/com/puppycrawl/tools/checkstyle/checks/indentation/indentation';

sub slurp_utf8 {
  my ($file) = @_;
  open my $fh, '<:encoding(UTF-8)', $file or die "Cannot read $file: $!";
  local $/;
  return <$fh>;
}

my @examples = (
  { n => 1,
    config => ['To configure the default check:'],
    code => ['Example of Compliant code for default configuration',
             '(in comment name of property that controls indentations):'] },
  { n => 2,
    config => ['To configure the check to enforce the indentation style recommended by',
               'Oracle:'],
    code => ['Example of Compliant code for default configuration',
             '(in comment name of property that controls indentation):'] },
  { n => 3,
    config => ['To configure the Check to enforce strict condition in line-wrapping validation.'],
    code => ["Such config doesn't allow next cases",
             'even code is aligned further to the right for better reading:'] },
  { n => 4,
    code => ['But if forceStrictCondition = false, this code is valid:'] },
  { n => 5,
    config => ['To configure the check for two-space block indentation:'],
    code => ['Example of compliant code where basicOffset makes each new block level use two spaces:'] },
  { n => 6,
    config => ['To configure the check for eight-space line wrapping indentation:'],
    code => ['Example of compliant code where continuation lines use lineWrappingIndentation:'] },
  { n => 7,
    config => ['To configure the check for eight-space throws clause indentation:'],
    code => ['Example of compliant code where throwsIndent controls throws clauses on new lines:'] },
  { n => 8,
    config => ['To configure the check for two-space array initialization indentation:'],
    code => ['Example of compliant code where arrayInitIndent controls array elements on new lines:'] },
  { n => 9,
    config => ['To configure the check for two-space brace adjustment:'],
    code => ['Example of compliant code where braceAdjustment controls braces on new lines:'] },
);

sub escape_xml {
  my ($text) = @_;
  $text =~ s/&/&amp;/g;
  $text =~ s/</&lt;/g;
  $text =~ s/>/&gt;/g;
  return $text;
}

sub paragraph {
  my ($id, $lines) = @_;
  print qq{        <p id="$id">\n};
  for my $line (@$lines) {
    print qq{          $line\n};
  }
  print qq{        </p>\n};
}

sub render_block {
  my ($language, $content) = @_;
  $content = escape_xml($content);
  chomp $content;
  print qq{        <div class="wrapper"><pre class="prettyprint"><code class="language-$language">\n};
  print $content . "\n";
  print qq{</code></pre></div>};
}

sub read_config {
  my ($text) = @_;
  $text =~ m{/\*xml\n(.*?)\n\*/}s or die 'No xml config found';
  return $1;
}

sub read_code {
  my ($text) = @_;
  $text =~ m{// xdoc section -- start\n(.*?)\n// xdoc section -- end}s or die 'No xdoc section found';
  return $1;
}

print qq{      <subsection name="Examples" id="Indentation_Examples">\n};
for my $i (0 .. $#examples) {
  my $example = $examples[$i];
  my $n = $example->{n};
  my $text = slurp_utf8("$dir/Example$n.java");

  if ($example->{config}) {
    paragraph("Example$n-config", $example->{config});
    render_block('xml', read_config($text));
    print "\n";
  }

  paragraph("Example$n-code", $example->{code});
  render_block('java', read_code($text));
  if ($i != $#examples) {
    print qq{<hr class="example-separator"/>};
  }
  print "\n";
}
print qq{      </subsection>\n};
PL
